import React, { useState, useEffect } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "./Admin.css";

const STATUS_BADGE = { pending: "badge-yellow", active: "badge-green", completed: "badge-gray", cancelled: "badge-red" };
const STATUS_LABEL = { pending: "Chờ khai giảng", active: "Đang học", completed: "Đã kết thúc", cancelled: "Đã hủy" };
const INIT = { courseId: "", name: "", description: "", maxStudents: 30, startDate: "", endDate: "", status: "pending" };

export default function AdminClasses() {
  const [classes, setClasses] = useState([]);
  const [courses, setCourses] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null);
  const [assignModal, setAssignModal] = useState(null);
  const [selected, setSelected] = useState(null);
  const [form, setForm] = useState(INIT);
  const [assignTeacherId, setAssignTeacherId] = useState("");

  const fetch = () => {
    setLoading(true);
    Promise.all([api.get("/courses"), api.get("/users")])
      .then(([c, u]) => {
        setCourses(c.data.data || []);
        const allUsers = u.data.data || [];
        setTeachers(allUsers.filter(x => x.roleId === 2 && x.approved));
        // Lấy classes từ tất cả courses
        return Promise.all((c.data.data || []).map(course =>
          api.get(`/courses/${course.id}/modules`).catch(() => ({ data: { data: [] } }))
        ));
      })
      .catch(() => {})
      .finally(() => setLoading(false));

    api.get("/courses").then(r => {
      // Lấy danh sách classes
      api.get("/admin/stats").catch(() => {});
    });
    // Gọi trực tiếp classes endpoint
    api.get("/admin/classes").catch(() => {}).then(r => {
      if (r?.data?.data) setClasses(r.data.data);
    });
  };

  // Fallback: lấy classes từ mỗi course
  const fetchClasses = async () => {
    setLoading(true);
    try {
      const [coursesRes, usersRes] = await Promise.all([api.get("/courses"), api.get("/users")]);
      setCourses(coursesRes.data.data || []);
      setTeachers((usersRes.data.data || []).filter(x => x.roleId === 2 && x.approved));
      // Lấy tất cả classes
      const res = await api.get("/admin/classes").catch(() => ({ data: { data: [] } }));
      setClasses(res.data.data || []);
    } catch {
      toast.error("Không thể tải dữ liệu");
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchClasses(); }, []);

  const handleSave = async () => {
    try {
      const payload = { ...form, courseId: Number(form.courseId), maxStudents: Number(form.maxStudents) };
      if (modal === "add") await api.post("/admin/classes", payload);
      else await api.put(`/admin/classes/${selected.id}`, payload);
      toast.success("Thành công"); setModal(null); fetchClasses();
    } catch (e) { toast.error(e.response?.data?.message || "Thất bại"); }
  };

  const handleAssignTeacher = async () => {
    if (!assignTeacherId) { toast.error("Chọn giáo viên"); return; }
    try {
      await api.put(`/admin/classes/${assignModal.id}/assign-teacher/${assignTeacherId}`);
      toast.success("Phân công thành công"); setAssignModal(null); fetchClasses();
    } catch { toast.error("Thất bại"); }
  };

  const getCourse = (id) => courses.find(c => c.id === id || c.id === Number(id));

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Quản lý lớp học</h1>
        <p>Tạo lớp học và phân công giáo viên</p>
      </div>

      <div className="toolbar">
        <div className="toolbar-left" />
        <button className="btn btn-primary" onClick={() => { setForm(INIT); setSelected(null); setModal("add"); }}>
          + Tạo lớp mới
        </button>
      </div>

      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead>
              <tr><th>Tên lớp</th><th>Khóa học</th><th>Sĩ số</th><th>Thời gian</th><th>Trạng thái</th><th>Thao tác</th></tr>
            </thead>
            <tbody>
              {classes.length === 0
                ? <tr><td colSpan={6} className="empty-state"><p>Chưa có lớp học nào</p></td></tr>
                : classes.map(c => {
                  const course = getCourse(c.courseId);
                  return (
                    <tr key={c.id}>
                      <td style={{ fontWeight: 500 }}>{c.name}</td>
                      <td>
                        <span className="badge badge-blue">{course?.examType || "—"}</span>
                        <span style={{ marginLeft: 6, fontSize: "0.85rem" }}>{course?.title || "—"}</span>
                      </td>
                      <td>{c.currentStudents || 0}/{c.maxStudents}</td>
                      <td style={{ fontSize: "0.82rem", color: "var(--gray-500)" }}>
                        {c.startDate ? new Date(c.startDate).toLocaleDateString("vi-VN") : "—"} →{" "}
                        {c.endDate ? new Date(c.endDate).toLocaleDateString("vi-VN") : "—"}
                      </td>
                      <td><span className={`badge ${STATUS_BADGE[c.status]}`}>{STATUS_LABEL[c.status]}</span></td>
                      <td style={{ display: "flex", gap: 6 }}>
                        <button className="btn btn-warning btn-sm"
                          onClick={() => { setForm({ courseId: c.courseId, name: c.name, description: c.description || "", maxStudents: c.maxStudents, startDate: c.startDate || "", endDate: c.endDate || "", status: c.status }); setSelected(c); setModal("edit"); }}>
                          ✏️
                        </button>
                        <button className="btn btn-primary btn-sm" onClick={() => { setAssignModal(c); setAssignTeacherId(""); }}>
                          👨‍🏫 Phân công
                        </button>
                      </td>
                    </tr>
                  );
                })
              }
            </tbody>
          </table>
        )}
      </div>

      {/* Modal thêm/sửa lớp */}
      {modal && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ maxWidth: 540 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>{modal === "add" ? "Tạo lớp học mới" : "Chỉnh sửa lớp học"}</h3>
              <button className="modal-close" onClick={() => setModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-group"><label>Khóa học *</label>
                <select value={form.courseId} onChange={e => setForm({ ...form, courseId: e.target.value })}>
                  <option value="">Chọn khóa học</option>
                  {courses.map(c => <option key={c.id} value={c.id}>{c.examType} - {c.title}</option>)}
                </select>
              </div>
              <div className="form-group"><label>Tên lớp *</label>
                <input value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} placeholder="VD: IELTS_A_2025" />
              </div>
              <div className="form-group"><label>Mô tả</label>
                <textarea rows={2} value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />
              </div>
              <div className="form-row">
                <div className="form-group"><label>Sĩ số tối đa</label>
                  <input type="number" value={form.maxStudents} onChange={e => setForm({ ...form, maxStudents: e.target.value })} min={1} />
                </div>
                <div className="form-group"><label>Trạng thái</label>
                  <select value={form.status} onChange={e => setForm({ ...form, status: e.target.value })}>
                    <option value="pending">Chờ khai giảng</option>
                    <option value="active">Đang học</option>
                    <option value="completed">Đã kết thúc</option>
                    <option value="cancelled">Đã hủy</option>
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Ngày bắt đầu</label>
                  <input type="date" value={form.startDate} onChange={e => setForm({ ...form, startDate: e.target.value })} />
                </div>
                <div className="form-group"><label>Ngày kết thúc</label>
                  <input type="date" value={form.endDate} onChange={e => setForm({ ...form, endDate: e.target.value })} />
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={handleSave}>Lưu</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal phân công giáo viên */}
      {assignModal && (
        <div className="modal-overlay" onClick={() => setAssignModal(null)}>
          <div className="modal" style={{ maxWidth: 420 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Phân công giáo viên — {assignModal.name}</h3>
              <button className="modal-close" onClick={() => setAssignModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-group"><label>Chọn giáo viên</label>
                <select value={assignTeacherId} onChange={e => setAssignTeacherId(e.target.value)}>
                  <option value="">— Chọn giáo viên —</option>
                  {teachers.map(t => (
                    <option key={t.id} value={t.id}>
                      {t.name} {t.ieltsScore ? `(IELTS ${t.ieltsScore})` : ""} {t.toeicScore ? `(TOEIC ${t.toeicScore})` : ""}
                    </option>
                  ))}
                </select>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setAssignModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={handleAssignTeacher}>Phân công</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
